from flask import Flask, request, jsonify
from flask_bcrypt import Bcrypt
from flask_login import LoginManager, UserMixin, login_user, logout_user, current_user
import pyotp
from itsdangerous import URLSafeTimedSerializer as Serializer

app = Flask(__name__)
bcrypt = Bcrypt(app)
login_manager = LoginManager()
login_manager.init_app(app)

# In-memory user database for simplicity. Replace with a proper database in production.
users = {
    'user1': {'password': bcrypt.generate_password_hash('password1'), 'mfa_enabled': False},
    'user2': {'password': bcrypt.generate_password_hash('password2'), 'mfa_enabled': True}
}

class User(UserMixin):
    def __init__(self, id):
        self.id = id

@login_manager.user_loader
def load_user(id):
    return User(id)

@app.route('/api/login', methods=['POST'])
def login():
    username = request.json['username']
    password = request.json['password']
    
    if username in users and bcrypt.check_password_hash(users[username]['password'], password):
        user = User(username)
        login_user(user)
        
        # Check if MFA is enabled
        if users[username]['mfa_enabled']:
            totp = pyotp.TOTP(users[username].get('totp_secret')).now()
            return jsonify({'message': 'MFA required', 'otp': totp})
    
    return jsonify({'message': 'Invalid credentials'}), 401

@app.route('/api/direct-login', methods=['POST'])
def direct_login():
    username = request.json['username']
    password = request.json['password']
    
    if username in users and bcrypt.check_password_hash(users[username]['password'], password):
        user = User(username)
        login_user(user)
        
        return jsonify({'message': 'Logged in successfully'})
    
    return jsonify({'message': 'Invalid credentials'}), 401

@app.route('/api/verify-otp', methods=['POST'])
def verify_otp():
    username = request.json['username']
    otp = request.json['otp']
    
    if users[username]['mfa_enabled']:
        totp = pyotp.TOTP(users[username].get('totp_secret')).now()
        
        if str(totp) == str(otp):
            return jsonify({'message': 'MFA verified successfully'})
    
    return jsonify({'message': 'Invalid OTP'}), 401

@app.route('/api/disable-mfa', methods=['POST'])
def disable_mfa():
    username = request.json['username']
    
    if users[username]['mfa_enabled']:
        del users[username]['totp_secret']
        users[username]['mfa_enabled'] = False
        
        return jsonify({'message': 'MFA disabled successfully'})
    
    return jsonify({'message': 'MFA is already disabled'}), 400

if __name__ == '__main__':
    app.run(debug=True)